<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">新資本フレームワーク概観(6月29日発表)</text>
  <g font-family="sans-serif">
    <rect x="20" y="55" width="205" height="90" rx="10" fill="#1c1c1f" stroke="#3f3f46" stroke-width="1.2"/>
    <text x="122" y="80" fill="#a1a1aa" font-size="13" text-anchor="middle">ビットコイン売却権限</text>
